12	function compareBuffers(a: ArrayBuffer, b: ArrayBuffer): boolean {
13	  const viewA = new Uint8Array(a);
14	  const viewB = new Uint8Array(b);
15	  if (viewA.byteLength !== viewB.byteLength) return false;
16	  for (let i = 0; i < viewA.byteLength; i++) {
17	    if (viewA[i] !== viewB[i]) return false;
18	  }
19	  return true;
20	}
