105	function restoreSession(): Session | null {
106	  try {
107	    for (let i = 0; i < localStorage.length; i++) {
108	      const key = localStorage.key(i);
109	      if (key && key.startsWith('session_')) {
110	        const raw = localStorage.getItem(key);
111	        if (raw) {
112	          const parsed: Session = JSON.parse(raw);
113	          if (parsed.expires_at > Date.now()) {
114	            authStore.set(parsed);
115	            return parsed;
116	          }
117	          // Stale вЂ” remove
118	          localStorage.removeItem(key);
119	        }
120	      }
121	    }
122	  } catch {
123	    // localStorage may be unavailable
124	  }
125	  return null;
126	}
